```mlir
  firrtl.circuit  "foo" {
   firrtl.module @foo() {
    %c = firrtl.constant 0 : !firrtl.uint<0>
    %1455 = builtin.unrealized_conversion_cast %c : !firrtl.uint<0> to i0
